@app.post("/upload/image")
async def upload_image(
    file: UploadFile = File(...),
    label: str = Form(...),
    contributor: Optional[str] = Form(None),
):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file upload.")
    try:
        image_path = save_image_bytes(content, file.filename or "upload.png")
        insert_example(
            image_path=image_path,
            label=label.strip(),
            source="image_upload",
            contributor=contributor,
            metadata={"filename": file.filename},
        )
        return {"status": "ok", "image_path": image_path, "label": label}
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to process image: {e}")


@app.post("/upload/csv")
async def upload_csv(
    file: UploadFile = File(...),
    contributor: Optional[str] = Form(None),
):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty CSV upload.")
    try:
        df = pd.read_csv(io.BytesIO(content))
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to read CSV: {e}")

    required = {"label"}
    if not required.issubset(df.columns):
        raise HTTPException(status_code=400, detail="CSV must include at least a 'label' column and either 'image_path' or 'image_base64'.")

    accepted = 0
    errors = []
    for idx, row in df.iterrows():
        try:
            label = str(row["label"]).strip()
            if not label:
                raise ValueError("Missing label")

            if "image_path" in df.columns and pd.notna(row.get("image_path")):
                src_path = Path(str(row["image_path"]))
                if not src_path.exists():
                    raise ValueError(f"image_path not found: {src_path}")
                img = Image.open(src_path).convert("RGB")
                buf = io.BytesIO()
                img.save(buf, format="PNG")
                image_path = save_image_bytes(buf.getvalue(), src_path.name)
            else:
                raise ValueError("CSV rows must provide a valid image_path column")

            insert_example(
                image_path=image_path,
                label=label,
                source="csv_upload",
                contributor=contributor,
                metadata={"row_index": int(idx), "filename": file.filename},
            )
            accepted += 1
        except Exception as e:
            errors.append({"row": int(idx), "error": str(e)})

    return {"status": "ok", "accepted": accepted, "errors": errors[:100]}


@app.post("/upload/zip")
async def upload_zip(
    file: UploadFile = File(...),
    contributor: Optional[str] = Form(None),
):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty ZIP upload.")

    tmp_dir = UPLOADS_DIR / uuid.uuid4().hex
    tmp_dir.mkdir(parents=True, exist_ok=True)
    zip_path = tmp_dir / sanitize_filename(file.filename or "dataset.zip")

    try:
        with open(zip_path, "wb") as f:
            f.write(content)

        accepted = 0
        errors = []

        with zipfile.ZipFile(zip_path, "r") as zf:
            zf.extractall(tmp_dir)

        labels_csv = tmp_dir / "labels.csv"
        if labels_csv.exists():
            df = pd.read_csv(labels_csv)
            if not {"filename", "label"}.issubset(df.columns):
                raise ValueError("labels.csv must contain 'filename' and 'label' columns.")
            for idx, row in df.iterrows():
                try:
                    img_file = tmp_dir / str(row["filename"])
                    if not img_file.exists():
                        raise ValueError(f"Missing file: {img_file}")
                    with open(img_file, "rb") as imgf:
                        image_path = save_image_bytes(imgf.read(), img_file.name)
                    insert_example(
                        image_path=image_path,
                        label=str(row["label"]).strip(),
                        source="zip_upload_csv_mapping",
                        contributor=contributor,
                        metadata={"archive": file.filename, "row_index": int(idx)},
                    )
                    accepted += 1
                except Exception as e:
                    errors.append({"row": int(idx), "error": str(e)})
        else:
            for class_dir in tmp_dir.iterdir():
                if class_dir.is_dir():
                    label = class_dir.name
                    for img_file in class_dir.rglob("*"):
                        if img_file.is_file() and img_file.suffix.lower() in ALLOWED_IMAGE_EXTS:
                            try:
                                with open(img_file, "rb") as imgf:
                                    image_path = save_image_bytes(imgf.read(), img_file.name)
                                insert_example(
                                    image_path=image_path,
                                    label=label,
                                    source="zip_upload_folder_structure",
                                    contributor=contributor,
                                    metadata={"archive": file.filename},
                                )
                                accepted += 1
                            except Exception as e:
                                errors.append({"file": str(img_file), "error": str(e)})

        return {"status": "ok", "accepted": accepted, "errors": errors[:100]}
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to process ZIP: {e}")
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)


@app.post("/train")
def train(req: TrainRequest):
    if train_status["running"]:
        raise HTTPException(status_code=409, detail="Training already in progress.")
    thread = threading.Thread(
        target=run_training,
        kwargs={"epochs": max(1, req.epochs), "image_size": (max(32, req.image_width), max(32, req.image_height))},
        daemon=True,
    )
    thread.start()
    return {"status": "started", "config": req.dict()}


@app.get("/status")
def status():
    return train_status


@app.get("/examples")
def examples(limit: int = 100):
    rows = list_examples()[: max(1, min(limit, 1000))]
    return {"count": len(rows), "examples": rows}


@app.get("/stats/labels")
def stats_labels():
    return {"labels": count_labels()}


@app.get("/models/latest")
def latest_model():
    if not train_status["last_model_path"]:
        return JSONResponse(status_code=404, content={"detail": "No trained model available."})
    return {
        "model_path": train_status["last_model_path"],
        "metrics": train_status["last_metrics"],
    }


